    @_doc_tv_atomic_store_rmw_op(testoutput=(0 ^ 1))
    @stub
    def atomic_store_xor(self, index: Shape, update: Tile, /) -> None:
        """Atomically applies bitwise XOR of `update` to the |tiled view| at the given tile `index`.

