async def call(callee_var: Var, args, kwargs) -> Var | None:
    builder = ir.Builder.get_current()
    callee_ty = callee_var.get_type()
    if isinstance(callee_ty, FunctionTy):
        return await _call_function(callee_ty.func, args, kwargs, builder)
    elif isinstance(callee_ty, BoundMethodTy):
        bound_method = callee_var.get_aggregate()
        assert isinstance(bound_method, BoundMethodValue)
        return await _call_function(callee_ty.func, (bound_method.bound_self, *args), kwargs,
                                    builder)
    elif isinstance(callee_ty, DTypeConstructor):
        arg_list = _bind_args(_DTYPE_CONSTRUCTOR_SIGNATURE, callee_ty.dtype.name, args, kwargs)
        [x] = arg_list
        return dtype_constructor(callee_ty.dtype, x)
    elif isinstance(callee_ty, ClosureTy):
        func_name = callee_ty.func_hir.desc.name
        if func_name is None:
            func_name = callee_ty.func_hir.desc.short_str()
        arg_list = _bind_args(callee_ty.func_hir.signature, func_name, args, kwargs,
                              callee_var.get_aggregate().default_values)
        parent_scopes = _get_closure_parent_scopes(callee_ty, callee_var.get_aggregate(),
                                                   builder.ir_ctx)
        return await _call_user_defined(callee_ty.func_hir, arg_list, builder, parent_scopes)
    elif isinstance(callee_ty, TypeTy) and dataclasses.is_dataclass(callee_ty.ty):
        dataclass_info = get_dataclass_info(callee_ty.ty)
        param_names = tuple(dataclass_info.init_signature.parameters)
        # Add an extra `None` to args for the `self` parameter
        arg_list = _bind_args(dataclass_info.init_signature, callee_ty.ty.__name__,
                              (None, *args), kwargs)
        assert len(dataclass_info.field_names) + 1 == len(arg_list)
        items = tuple(arg_list[param_names.index(name)] for name in dataclass_info.field_names)
        return build_dataclass_instance(items, dataclass_info)
    elif isinstance(callee_ty, TypeTy) and callee_ty.ty is PointerInfo:
        arg_list = _bind_args(_POINTER_INFO_SIGNATURE, "PointerInfo", args, kwargs)
        return await _call_builtin(PointerInfo, arg_list, builder)
    elif isinstance(callee_ty, TypeTy) and issubclass(callee_ty.ty, Enum):
        if len(args) != 1 or kwargs:
            raise TileTypeError("Enum constructor takes exactly one positional argument")
        arg = args[0]

def add_operation(self, op_class,
                  result_ty: T,
                  attrs_and_operands: Mapping,
                  result: Var | None = None) -> Var[T]:
    assert isinstance(result_ty, Type)
    return self._add_operation(op_class, result_ty, attrs_and_operands, result)

def add_operation_variadic(self, op_class,
                           result_types: tuple[Type, ...],
                           attrs_and_operands: Mapping,
                           result: Var | None = None) -> tuple[Var, ...]:
    assert isinstance(result_types, tuple)
    return self._add_operation(op_class, result_types, attrs_and_operands, result)

def _add_operation(self, op_class,
                   result_ty: Type | None | Tuple[Type | None, ...],
                   attrs_and_operands: Mapping,
                   result: Var | Sequence[Var] | None = None) -> Var | Tuple[Var, ...]:
    if self.block_restriction is not None:
        self.block_restriction.validate_operation(op_class)

    assert not self.is_terminated
    force_type = False
    if isinstance(result_ty, tuple):
        if result is None:
            result = tuple(self.ir_ctx.make_temp(self._loc) for _ in result_ty)
        else:
            result = tuple(result)
            assert all(isinstance(v, Var) for v in result)
            force_type = True

        for var, ty in zip(result, result_ty, strict=True):
            if ty is not None:
                var.set_type(ty, force=force_type)

        result_vars = result
    else:
        if result is None:
            result = self.ir_ctx.make_temp(self._loc)
        else:
            assert isinstance(result, Var)
            force_type = True
        if result_ty is not None:
            result.set_type(result_ty, force=force_type)

        result_vars = (result,)

    new_op = op_class(**attrs_and_operands, loc=self._loc, result_vars=result_vars)
    self._ops.append(new_op)
    if new_op.is_terminator:
        self.is_terminated = True
    return result

def make_aggregate(self,
                   value: AggregateValue,
                   ty: Type | None,
                   loose_ty: Type | None = None,
                   result_var: Var | None = None) -> Var:
    force_type = True
    if result_var is None:
        result_var = self.ir_ctx.make_temp(self._loc)
        force_type = False

    if ty is not None:
        result_var.set_type(ty, force=force_type)
    if loose_ty is not None:
        result_var.set_loose_type(ty, force=force_type)
    result_var.set_aggregate(value)
    return result_var

